import os
from datetime import datetime

TEMPLATE = """<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Análisis Geográfico de Riesgo Sectorial - Solo Alto Riesgo</title><link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/><script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script><script src="https://cdn.jsdelivr.net/npm/chart.js"></script><link rel="stylesheet" href="https://cdn.datatables.net/1.13.7/css/jquery.dataTables.min.css"><script src="https://code.jquery.com/jquery-3.7.0.min.js"></script><script src="https://cdn.datatables.net/1.13.7/js/jquery.dataTables.min.js"></script><style>:root{--primary:#1b263b;--secondary:#415a77;--accent:#00b4d8;--danger:#e63946;--warning:#f77f00;--success:#2a9d8f}*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;background:linear-gradient(135deg,#f5f7fa 0%,#c3cfe2 100%);color:#333;line-height:1.6}.container{max-width:1500px;margin:0 auto;padding:20px}header{background:linear-gradient(135deg,var(--primary),var(--secondary));color:#fff;padding:35px 20px;text-align:center;border-radius:15px;margin-bottom:30px;box-shadow:0 10px 30px rgba(27,38,59,.4)}.logo-image{height:48px;display:block;margin:0 auto 10px auto;filter:drop-shadow(0 2px 4px rgba(0,0,0,.3))}header h1{font-size:2.5em;margin-bottom:8px}header p{font-size:1.2em;opacity:.9}.kpi-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:20px;margin-bottom:30px}.kpi-card{background:#fff;padding:22px;border-radius:12px;box-shadow:0 5px 15px rgba(0,0,0,.1);text-align:center}.kpi-value{font-size:2.4em;font-weight:700;color:var(--danger)}.kpi-label{color:#666;font-size:.95em}.section{background:#fff;border-radius:12px;padding:25px;margin-bottom:30px;box-shadow:0 5px 20px rgba(0,0,0,.08)}.section h2{color:var(--primary);margin-bottom:20px;font-size:1.6em;border-bottom:3px solid var(--accent);padding-bottom:10px;display:inline-block}.dual-section{display:grid;grid-template-columns:380px 1fr;gap:25px;margin-bottom:30px;align-items:start}.chart-box{background:#fff;padding:20px;border-radius:12px;box-shadow:0 5px 20px rgba(0,0,0,.08);height:420px;display:flex;flex-direction:column;justify-content:center}.map-world-box{background:#fff;padding:15px;border-radius:12px;box-shadow:0 5px 20px rgba(0,0,0,.08);height:420px}#mapWorld{height:100%;border-radius:8px}#mapColombia{height:500px;border-radius:10px;margin-bottom:15px}.legend{background:#fff;padding:12px;border-radius:8px;box-shadow:0 2px 10px rgba(0,0,0,.1);font-size:.9em;margin-top:10px}.legend i{width:18px;height:18px;float:left;margin-right:8px;border-radius:50%;opacity:.8}.badge-high{background:var(--danger);color:#fff;padding:6px 14px;border-radius:20px;font-weight:bold;font-size:.8em}@media (max-width:1100px){.dual-section{grid-template-columns:1fr}.chart-box,.map-world-box{height:400px}}@media (max-width:768px){header h1{font-size:2em}#mapColombia{height:350px}}</style></head><body><div class="container"><header><h1>Análisis de Riesgo Sectorial</h1><p>Transacciones de ALTO RIESGO detectadas por CIIU y zona geográfica</p></header><div class="kpi-grid"><div class="kpi-card"><div class="kpi-value">0</div><div class="kpi-label">Transacciones Alto Riesgo</div></div><div class="kpi-card"><div class="kpi-value">0</div><div class="kpi-label">Empresas Involucradas</div></div><div class="kpi-card"><div class="kpi-value">$0</div><div class="kpi-label">Monto Total Alto Riesgo</div></div></div><div class="section"><h2>Mapa de Transacciones Alto Riesgo - Colombia</h2><div id="mapColombia"></div></div><div class="dual-section"><div class="chart-box"><h2 style="text-align:center; margin-bottom:15px; color:var(--primary);">Distribución por CIIU</h2><canvas id="riskChart"></canvas></div><div class="map-world-box"><h2 style="text-align:center; margin-bottom:10px; color:var(--primary);">Mapa Global FATF/GAFI</h2><div id="mapWorld"></div></div></div><div class="section"><h2>Detalle de Transacciones Alto Riesgo</h2><table id="transaccionesTable" class="display" style="width:100%"><thead><tr><th>Monto</th><th>Empresa</th><th>NIT</th><th>CIIU</th><th>Actividad</th><th>Departamento</th></tr></thead><tbody></tbody></table></div><div class="section"><h2>Recomendaciones Automatizadas - Alto Riesgo</h2><div style="background:#ffeaea; padding:20px; border-radius:10px; border-left:6px solid var(--danger);"><ul style="margin:15px 0; font-size:1.05em;"><li>Monitoreo diario obligatorio de todas las operaciones</li><li>KYC reforzado con verificación de beneficiarios finales</li><li>Validación documental 100%</li><li>Auditoría interna trimestral</li><li>Revisión por Comité de Riesgo en máximo 48 horas</li></ul></div></div></div><script>const mapCol=L.map('mapColombia').setView([4.5709,-74.2973],6);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapCol);const altoRiesgo=[];altoRiesgo.forEach(z=>{L.circleMarker(z.coords,{radius:20,color:'#e63946',weight:4,fillColor:'#e63946',fillOpacity:.8}).addTo(mapCol).bindPopup(`<strong>${z.name}</strong><br>Empresa: ${z.empresa}<br>CIIU: ${z.ciiu}<br>Monto: ${z.monto}<br><b style='color:#e63946'>ALTO RIESGO</b>`)});new Chart(document.getElementById('riskChart'),{type:'doughnut',data:{labels:[],datasets:[{data:[],backgroundColor:['#e63946','#c1121f','#9b2226'],borderWidth:3,borderColor:'#fff'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{padding:15}}}}});const mapWorld=L.map('mapWorld').setView([20,0],2);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapWorld);const GEOJSON_URL='https://raw.githubusercontent.com/johan/world.geo.json/master/countries.geo.json';const statusByCountry={};function normalize(s){return(s||'').normalize('NFD').replace(/[\\u0300-\\u036f]/g,'').trim().toUpperCase()}function getStatus(n){const k=normalize(n);return statusByCountry[k]||null}fetch(GEOJSON_URL).then(r=>r.json()).then(geo=>{L.geoJson(geo,{style:f=>({fillColor:getStatus(f.properties.name)==='COOPERANTE'?'#2ca25f':getStatus(f.properties.name)==='NO COOPERANTE'?'#de2d26':'#cccccc',weight:.5,color:'#555',fillOpacity:.7}),onEachFeature:(f,l)=>l.bindPopup(`<b>${f.properties.name}</b><br>FATF: <strong>${getStatus(f.properties.name)||'Sin datos'}</strong>`) }).addTo(mapWorld)});$(document).ready(()=>$('#transaccionesTable').DataTable({language:{url:'https://cdn.datatables.net/plug-ins/1.13.7/i18n/es-ES.json'},pageLength:10}))</script></body></html>"""

def generate_html(path: str | None = None) -> str:
    if not path:
        path = os.path.join(os.getcwd(), "analisis_geografico_mapas (1).html")
    with open(path, "w", encoding="utf-8") as f:
        f.write(TEMPLATE)
    return path
